// Flux séquentiel : Météo → Emails → Formater
// $input contient les emails (dernier node), $('Météo du jour') la météo
let weatherNode = {};
try { weatherNode = $('Météo du jour').first().json; } catch(e) {}

const emailItems = $input.all();

let weatherSummary;
try {
  if (!weatherNode.main) {
    weatherSummary = 'Météo temporairement indisponible';
  } else {
    weatherSummary = `${weatherNode.weather[0].description}, ${Math.round(weatherNode.main.temp)}°C (ressenti ${Math.round(weatherNode.main.feels_like)}°C)`;
  }
} catch(e) {
  weatherSummary = 'Météo indisponible';
}

let emailSummary = 'Emails non disponibles.';
let emailCount = 0;
try {
  const validEmails = emailItems.filter(e => e.json && !e.json.error);
  emailCount = validEmails.length;
  if (emailCount === 0) {
    emailSummary = 'Aucun email non lu.';
  } else {
    emailSummary = validEmails.map(e => {
      const d = e.json;
      const from = d.from || d.payload?.headers?.find(h => h.name === 'From')?.value?.split('<')[0]?.trim() || 'Inconnu';
      const snippet = d.snippet || d.bodyPreview || '';
      return `• ${from}: ${snippet.substring(0, 80)}...`;
    }).join('\n');
  }
} catch(e) {
  emailSummary = 'Erreur lecture emails: ' + e.message;
}

const now = new Date();
const greeting = now.getHours() < 12 ? 'Bonjour' : 'Bonsoir';
const dateStr = now.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

return [{ json: {
  briefing: `${greeting} Abo ! Nous sommes le ${dateStr}.\n\n🌤️ Météo : ${weatherSummary}.\n\n📧 Emails importants :\n${emailSummary}`,
  weather: weatherSummary,
  email_count: emailCount
}}];
